## Rendering Skill Views

Skill Views are the equivalent of pages in a "standard" web application. They are accessible via the url in 2 ways.

1. Subdomain: `https://{skillNamespace}.spruce.bot` (will render your `RootSkillViewController`)
2. Hash: `https://spruce.bot/#/views/{skillNamespace}.{viewId}`

### Root Skill View

Let's get started on rendering a `RootSkillView`.

<details>
<summary><strong>Test 1</strong>: Load Your (Root) Skill View</summary>

We'll start with the `RootSkillViewController`. All you have to do to start is try and load your Skill View and the test will fail.

```ts
import {
    AbstractSpruceFixtureTest
} from '@sprucelabs/spruce-test-fixtures'

export default class RootSkillViewTest extends AbstractSpruceFixtureTest {
    @test()
    protected async canLoadRootSkillView() {
        this.views.Controller('eightbitstories.root', {}),
    }
}
```

</details>

<details>
<summary><strong>Production 1</strong>: Create Your Root Skill View</summary>

This part is pretty easy! Run this following command and follow the instructions!

```shell
spruce create.view
```

</details>

### Rendering A Different Skill View

Beyond your `RootSkillViewController`, you can create additional `SkillViewControllers` — each one is like a separate page in your `Skill`. They are identified by their `static id` property and are accessed at `https://spruce.bot/#/views/{skillNamespace}.{viewId}`.

<details>
<summary><strong>Test 1</strong>: Instantiate a new Skill View</summary>

```ts
import { AbstractSpruceFixtureTest } from '@sprucelabs/spruce-test-fixtures'

export default class OnboardingSkillViewTest extends AbstractSpruceFixtureTest {
    @test()
    protected async canCreateOnboardingSkillView() {
        // Step 1. Try to instantiate the Skill View (will fail until you create it)
        this.views.Controller('eightbitstories.onboarding', {})
    }
}
```

</details>

<details>
<summary><strong>Production 1</strong>: Create a new Skill View</summary>

```shell
spruce create.view
```

The CLI will walk you through the following prompts:

1. **"Which are you creating?"** — Select "Skill View Controller".
2. **"Make this the Root View Controller?"** — Select No.
3. **"Controller name"** — Enter the name of your `SkillView` (e.g. "Onboarding").

The generated file will be placed at `src/skillViewControllers/Onboarding.svc.ts` with a `static id` matching your name:

```ts
import {
    AbstractSkillViewController,
    SkillView,
} from '@sprucelabs/heartwood-view-controllers'

export default class OnboardingSkillViewController extends AbstractSkillViewController {
    public static id = 'onboarding'

    public render(): SkillView {
        return {
            layouts: [],
        }
    }
}
```

</details>

### Redirecting Between Skill Views

Use `router.redirect()` to navigate between `SkillViews`. The `router` is available in the `load()` method via `SkillViewControllerLoadOptions`.

<details>
<summary><strong>Test 1</strong>: Assert redirect on button click</summary>

```ts
import { AbstractSpruceFixtureTest } from '@sprucelabs/spruce-test-fixtures'
import {
    vcAssert,
    interactor,
} from '@sprucelabs/heartwood-view-controllers'

export default class OnboardingSkillViewTest extends AbstractSpruceFixtureTest {
    private vc!: OnboardingSkillViewController

    protected async beforeEach() {
        await super.beforeEach()
        this.vc = this.views.Controller('eightbitstories.onboarding', {})
        await this.views.load(this.vc)
    }

    @test()
    protected async redirectsToDashboardOnComplete() {
        // Step 1. Assert clicking the "done" button redirects to the root Skill View
        await vcAssert.assertActionRedirects({
            action: () => interactor.clickButton(this.vc, 'done'),
            router: this.views.getRouter(),
            destination: {
                id: 'eightbitstories.root',
            },
        })
    }
}
```

</details>

<details>
<summary><strong>Production 1</strong>: Redirect on button click</summary>

```ts
import {
    AbstractSkillViewController,
    CardViewController,
    Router,
    SkillView,
    SkillViewControllerLoadOptions,
    ViewControllerOptions,
} from '@sprucelabs/heartwood-view-controllers'

export default class OnboardingSkillViewController extends AbstractSkillViewController {
    public static id = 'onboarding'
    private cardVc: CardViewController
    private router!: Router

    public constructor(options: ViewControllerOptions) {
        super(options)
        this.cardVc = this.CardVc()
    }

    private CardVc() {
        return this.Controller('card', {
            header: {
                title: 'Welcome!',
            },
            footer: {
                buttons: [
                    {
                        id: 'done',
                        label: 'Get Started',
                        type: 'primary',
                        // Step 2. Wire the button's onClick to the redirect handler
                        onClick: this.handleClickDone,
                    },
                ],
            },
        })
    }

    public async load(options: SkillViewControllerLoadOptions) {
        const { router } = options
        // Step 1. Save the router for later use
        this.router = router
    }

    // Step 3. Redirect to the root Skill View when clicked
    private handleClickDone = async () => {
        await this.router.redirect('eightbitstories.root' as any)
    }

    public render(): SkillView {
        return {
            layouts: [
                {
                    cards: [this.cardVc.render()],
                },
            ],
        }
    }
}
```

</details>

You can also pass arguments when redirecting:

```ts
await this.router.redirect('eightbitstories.dashboard' as any, { storyId: '123' })
```

The destination `SkillView` receives these via `args` in its `load()` options:

```ts
public async load(options: SkillViewControllerLoadOptions) {
    const { args } = options

