import { vcAssert } from '@sprucelabs/heartwood-view-controllers'

export default class RootSkillViewTest extends AbstractSpruceFixtureTest {
    private vc!: RootSkillViewController

    protected async beforeEach() {
        await super.beforeEach()
        this.vc = this.views.Controller('eightbitstories.root', {})
    }

    @test()
    protected async isScopedByOrganization() {
        // Step 1. Assert the SkillView requires organization scope
        vcAssert.assertSkillViewScopedBy(this.vc, 'organization')
    }
}
```

</details>

<details>
<summary><strong>Production 1</strong>: Require an organization</summary>

```ts
import {
    AbstractSkillViewController,
    ScopeFlag, // Step 2. Import ScopeFlag (fixes type error from Step 1)
    SkillView,
} from '@sprucelabs/heartwood-view-controllers'

export default class RootSkillViewController extends AbstractSkillViewController {
    public static id = 'root'

    // Step 1. Override getScope to require an organization
    public getScope = () => ['organization'] as ScopeFlag[]

    public render(): SkillView {
        return {
            layouts: [],
        }
    }
}
```

> **Note**: You can combine flags. For example, `['employed', 'location']` requires the person to be employed at the selected `Location`.

</details>

### Loading Data

The `load()` method is called after all prerequisites are met (login, scope). This is where you should do your heavy lifting: fetching data, setting up listeners, etc.

Your `SkillView` is already visible when `load()` is called. That means the person will see whatever `render()` returns before any data is loaded. Design your initial render to look good before data is loaded.

