        const client = await this.connectToApi()
        await client.on(
            'eightbitstories.did-update-story::v2024_01_01',
            this.handleDidUpdateStory
        )
    }

    // Step 2. Use an arrow function property so it can be passed as a reference
    private handleDidUpdateStory = async () => {
        this.triggerRender()
    }

    public async destroy() {
        // Step 3. Always call super.destroy() to clean up child controllers
        await super.destroy()

        // Step 4. Remove the listener we set up in load()
        const client = await this.connectToApi()
        await client.off(
            'eightbitstories.did-update-story::v2024_01_01',
            this.handleDidUpdateStory
        )
    }

    public render(): SkillView {
        return {
            layouts: [
                {
                    cards: [this.cardVc.render()],
                },
            ],
        }
    }
}
